pub fn fletcher16(buf: &[u8]) -> u16 {
    let mut s1: u16 = 0;
    let mut s2: u16 = 0;
    for &b in buf {
        s1 = (s1 + b as u16) % 255;
        s2 = (s2 + s1) % 255;
    }
    (s2 << 8) | s1
}

pub fn fletcher32(words: &[u16]) -> u32 {
    let mut s1: u32 = 0;
    let mut s2: u32 = 0;
    for &w in words {
        s1 = (s1 + w as u32) % 65535;
        s2 = (s2 + s1) % 65535;
    }
    (s2 << 16) | s1
}
